SELECT data_id, data_value, method
FROM water_quality_data
WHERE lab_id = 0 AND station_id = 0;

SELECT data_value 
FROM water_quality_data 
WHERE data_id = 1;

SELECT COUNT(*)
FROM water_quality_data
WHERE status = 'validated';

SELECT characteristic 
FROM characteristics
WHERE char_id = 1;

SELECT char_id, characteristic, unit
FROM characteristics
WHERE unit = 'mg/L';

SELECT CAST(COUNT(data_id) AS REAL) / COUNT(DISTINCT data_date) AS avg_entries_per_day
FROM water_quality_data
WHERE char_id=0;

SELECT characteristic, unit, description
FROM characteristics
WHERE char_id > 5;

SELECT data_value, data_date 
FROM water_quality_data 
WHERE char_id = 0 AND station_id = 1;

SELECT lab_name 
FROM laboratories 
WHERE lab_id NOT IN (SELECT lab_id FROM water_quality_data);

SELECT * 
FROM laboratories AS l 
INNER JOIN water_quality_data AS wqd ON l.lab_id = wqd.lab_id;
